fun processDocument(indexName: String, document: ProductDocument) {
    primaryIngester.add(BulkOperation.of { op -> op.index { idx -> idx.index(indexName).id(document.id).document(docMap) } })
}

fun updateAliasAndCleanup(alias: String, newIndexName: String, maxRetention: Int = 2) {
    esClient.indices().updateAliases { req ->
        existingIndices.forEach { oldIndex -> action.remove { r -> r.index(oldIndex).alias(alias) } }
        action.add { a -> a.index(newIndexName).alias(alias) }
    }
    existingIndices.sortedDescending().drop(maxRetention).forEach { esClient.indices().delete { it } }
}

fun createIndex(indexName: String) {
    esClient.indices().create { req -> req.index(indexName)
        .settings { s -> s.analysis { a -> a.analyzer("nori_analyzer") { an -> an.custom { c -> c.tokenizer("nori_tokenizer") } } } }
        .mappings { m -> m.properties("name") { p -> p.text { t -> t.analyzer("nori_analyzer") } } }
    }
}

